#include<bits/stdc++.h>
using namespace std;
long long n,m,q,x,y,root[300010];
vector<long long> v[300010];
struct segment_tree
{
    struct node
    {
        long long sum;
        long long lson,rson;
    }a[50000010];
    long long cnt;
    segment_tree():cnt(0){}
    void update(long long &x,long long l,long long r,long long p)
    {
        if(x==0)
        {
            x=++cnt;
        }
        if(l==r)
        {
            a[x].sum=1;
            return;
        }
        long long mid=(l+r)>>1;
        if(p<=mid)
        {
            update(a[x].lson,l,mid,p);
        }
        else
        {
            update(a[x].rson,mid+1,r,p);
        }
        a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
    }
    long long query(long long &x,long long l,long long r,long long p)
    {
        if(x==0)
        {
            x=++cnt;
        }
        if(l==r)
        {
            return l;
        }
        long long mid=(l+r)>>1;
        long long tmp=(mid-l+1)-a[a[x].lson].sum;
        if(p<=tmp)
        {
            return query(a[x].lson,l,mid,p);
        }
        else
        {
            return query(a[x].rson,mid+1,r,p-tmp);
        }
    }
}t;
long long val;
int main()
{
    scanf("%lld%lld%lld",&n,&m,&q);
    for(long long i=1;i<=q;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        if(y<m)
        {
            long long p=t.query(root[x],1,m-1+q,y);
            if(p<m)
            {
                val=(x-1)*m+p;
            }
            else
            {
                val=v[x][p-m];
            }
            printf("%lld\n",val);
            v[n+1].push_back(val);
            t.update(root[x],1,m-1+q,p);
            p=t.query(root[n+1],1,n+q,x);
            if(p<=n)
            {
                val=p*m;
            }
            else
            {
                val=v[n+1][p-n-1];
            }
            v[x].push_back(val);
            t.update(root[n+1],1,n+q,p);
        }
        else
        {
            long long p=t.query(root[n+1],1,n+q,x);
            if(p<=n)
            {
                val=p*m;
            }
            else
            {
                val=v[n+1][p-n-1];
            }
            printf("%lld\n",val);
            v[n+1].push_back(val);
            t.update(root[n+1],1,n+q,p);
        }
    }
    return 0;
}
